// Extract company name from filename instead of using unreliable array indexing
const item = $input.item;

// Get the filename from binary data
const binaryData = item.binary.data;
const fileName = binaryData.fileName || '';

// Extract company name (e.g., "bens-electrical.txt" -> "bens-electrical")
const companyName = fileName.replace('.txt', '');

// Add fields to the item
item.json.company = companyName;
item.json.transcript = item.json.text;
item.json.fileName = fileName;

return item;

const item = $input.item;

try {
  // Get the LLM response
  let llmResponse = item.json.message?.content || item.json.text || '';

  // Some LLM responses may wrap JSON in markdown code blocks
  llmResponse = llmResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse the JSON
  const parsed = JSON.parse(llmResponse);

  // Add parsed fields to item
  item.json.summary = parsed.summary;
  item.json.key_points = parsed.key_points;

  return item;

} catch (error) {
  // If parsing fails, create default values
  item.json.summary = "Error: Could not parse LLM response";
  item.json.key_points = ["Parsing error", "Check LLM output", "Verify JSON format"];
  item.json.error = error.message;
  item.json.raw_response = item.json.message?.content || item.json.text;

  return item;
}

const item = $input.item;

// Build the memo object in the exact format you need
const memo = {
  company: item.json.company,
  summary: item.json.summary,
  key_points: item.json.key_points,
  version: "v1",
  processed_at: new Date().toISOString()
};

item.json.memo = memo;

return item;
